import{_ as e,o as t,c as o,a3 as r}from"./chunks/framework.BTFg6ESq.js";const m=JSON.parse('{"title":"工具管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/tool-management.md","filePath":"user-guide/settings/tool-management.md","lastUpdated":1778239080000}'),l={name:"user-guide/settings/tool-management.md"};function i(n,a,s,h,d,u){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="工具管理" tabindex="-1">工具管理 <a class="header-anchor" href="#工具管理" aria-label="Permalink to &quot;工具管理&quot;">​</a></h1><blockquote><p>工具管理用于控制各工具在主页中的显示和默认排序。本篇将带你了解如何显示/隐藏工具、调整工具顺序以及重置设置。</p></blockquote><hr><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在设置左侧导航栏中点击「工具模块」选项卡。</li></ol><hr><h2 id="可见性控制" tabindex="-1">可见性控制 <a class="header-anchor" href="#可见性控制" aria-label="Permalink to &quot;可见性控制&quot;">​</a></h2><ul><li>每个工具项都是一个可点击的卡片。</li><li><strong>高亮（有边框） = 在主页显示</strong>。</li><li>支持<strong>全选 / 全不选</strong>批量操作。</li><li>实时显示<strong>已启用数 / 总数</strong>统计。</li></ul><hr><h2 id="排序管理" tabindex="-1">排序管理 <a class="header-anchor" href="#排序管理" aria-label="Permalink to &quot;排序管理&quot;">​</a></h2><ul><li>拖拽工具项左下角的 <strong>↕ (排序手柄)</strong> 调整在主页中的显示顺序。</li><li>拖拽时有倾斜样式反馈。</li><li>支持触摸设备。</li><li>拖拽结束后自动保存顺序，同步更新侧边栏和主页。</li></ul><hr><h2 id="重置顺序" tabindex="-1">重置顺序 <a class="header-anchor" href="#重置顺序" aria-label="Permalink to &quot;重置顺序&quot;">​</a></h2><p>点击「重置顺序」按钮，一键恢复为默认工具排列顺序。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-如何完全隐藏某个不需要的工具" tabindex="-1">Q：如何完全隐藏某个不需要的工具？ <a class="header-anchor" href="#q-如何完全隐藏某个不需要的工具" aria-label="Permalink to &quot;Q：如何完全隐藏某个不需要的工具？&quot;">​</a></h3><p>在「工具模块」设置面板中点击该工具卡片，取消其选中状态即可。工具不会从侧边栏删除，只是在主页隐藏。需要时重新选中即可恢复。</p><h3 id="q-隐藏工具后-它的功能还会初始化吗" tabindex="-1">Q：隐藏工具后，它的功能还会初始化吗？ <a class="header-anchor" href="#q-隐藏工具后-它的功能还会初始化吗" aria-label="Permalink to &quot;Q：隐藏工具后，它的功能还会初始化吗？&quot;">​</a></h3><p>取决于该工具是否注册了启动项。如果工具有启动项且已启用，即使隐藏它也会在后台初始化。建议同时关闭该工具的启动项。</p><hr><blockquote><p><strong>下一步</strong>：阅读 <a href="./about">关于与许可</a>，了解应用版本信息和开源生态。</p></blockquote>',22)])])}const q=e(l,[["render",i]]);export{m as __pageData,q as default};
